import base64
import zlib

def _decode(b64: str) -> str:
    """Decode a zlib-compressed, base64-encoded string."""
    return zlib.decompress(base64.b64decode(b64)).decode("utf-8")

_CSV_MOTOS = ""
CSV_MOTOS: str = _decode(_CSV_MOTOS)

_CSV_CARROS = ""
CSV_CARROS: str = _decode(_CSV_CARROS)

_CSV_CAMINHOES = ""
CSV_CAMINHOES: str = _decode(_CSV_CAMINHOES)

CSV_DATA = CSV_MOTOS
